import React from 'react';
import JobCard from './JobCard';

const JobList = ({ jobs, variant, onSelectJob }) => {
    // Layout Grid yang sangat responsif:
    // Pada HP, kartu akan otomatis mengisi 1 kolom penuh (minmax 280px)
    // Pada Desktop, kartu akan berjajar rapi ke samping (otomatis menyesuaikan jumlah kolom)
    const gridStyle = {
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
        gap: '16px', // Jarak antar kartu lebih rapat agar pas di layar kecil
        width: '100%',
        padding: '0 10px', // Memberikan ruang di sisi kiri-kanan layar HP
        boxSizing: 'border-box'
    };

    // Layout vertikal khusus jika ingin variant 'full' tetap list memanjang
    const listStyle = {
        display: 'flex',
        flexDirection: 'column',
        gap: '16px',
        width: '100%',
        maxWidth: '800px',
        margin: '0 auto',
        padding: '0 10px',
        boxSizing: 'border-box'
    };

    return (
        <div style={variant === 'simple' ? gridStyle : listStyle}>
            {jobs.map(job => (
                <div key={job.id} style={{ width: '100%' }}>
                    <JobCard 
                        job={job} 
                        isFull={variant === 'full'} 
                        onClick={() => onSelectJob && onSelectJob(job)}
                    />
                </div>
            ))}
        </div>
    );
};

export default JobList;
